添加必要的计算引擎
----
--包含DDL、DML、DQL、raise notice以及游标，其中DQL语句涉及简单查询和复杂查询，匿名代码段，包含入参和出参
-- 如果存储过程已经存在，先删除它
IF OBJECT_ID(&#039;dbo.GetEmployeeDetails_001&#039;, &#039;P&#039;) IS NOT NULL
DROP PROCEDURE dbo.GetEmployeeDetails_001;
-- 创建存储过程
CREATE PROCEDURE dbo.GetEmployeeDetails_001
@InputEmployeeID INT
AS
BEGIN
-- 声明局部变量以保存员工姓名和平均薪资
DECLARE @LocalEmployeeID INT,
@simple_result VARCHAR(500),
@complex_result VARCHAR(500),
@lambda_sign DECIMAL(10, 2),
@EmployeeName VARCHAR(100),
@AvgSalary DECIMAL(10, 2);
-- DQL: 简单查询
SELECT @simple_result = FirstName + &#039; &#039; + LastName
FROM sqlserver_table
WHERE EmployeeID = @InputEmployeeID;
-- DQL: 复杂查询
set @complex_result =
(SELECT CONCAT(EmployeeID, FirstName, LastName, Salary) AS complex_result
FROM sqlserver_table
WHERE Salary &gt; (SELECT AVG(Salary) FROM sqlserver_table));
-- RAISERROR: 抛出错误信息
IF @InputEmployeeID &gt; 5
BEGIN
RAISERROR(&#039;Employee not found&#039;, 16, 1);
END
-- 匿名代码段
SELECT @AvgSalary = AVG(Salary) FROM sqlserver_table;
PRINT &#039;Average Salary: &#039; + CAST(@AvgSalary AS NVARCHAR(50));
--输出结果
SELECT @InputEmployeeID AS InputEmployeeID, @simple_result AS simple_result, @complex_result AS complex_result, @AvgSalary AS AvgSalary;
END;
--建表
CREATE TABLE Customers (
CustomerID INT PRIMARY KEY,
Name NVARCHAR(100)
);
-- 插入示例数据
INSERT INTO Customers (CustomerID, Name) VALUES (1, N&#039;John Doe&#039;);
INSERT INTO Customers (CustomerID, Name) VALUES (2, N&#039;Jane Smith&#039;);
INSERT INTO Customers (CustomerID, Name) VALUES (3, N&#039;Michael Johnson&#039;);
-- 调用存储过程,@InputEmployeeID&gt;5时会抛出异常
EXEC dbo.GetEmployeeDetails_001  @InputEmployeeID = 1;

添加必要的计算引擎
----
--包含DDL、DML、DQL以及raise notice、以及游标，其中DQL语句涉及简单查询和复杂查询，匿名代码段，包含入参和出参
CREATE OR REPLACE FUNCTION oushu_procedure(IN search_term VARCHAR(255), OUT total_count INT, OUT matched_count INT)
RETURNS SETOF oushu_table
AS $$
DECLARE
-- 定义游标
cur CURSOR FOR
-- 简单查询：查找包含特定搜索词的所有记录
SELECT * FROM oushu_table WHERE description LIKE &#039;%&#039; || search_term || &#039;%&#039;;
-- 游标变量
rec oushu_table%ROWTYPE;
BEGIN
/*
-- 创建表（DDL）
CREATE TABLE IF NOT EXISTS oushu_table (
id SERIAL PRIMARY KEY,
name VARCHAR(100),
description TEXT
);

-- 插入数据（DML）
INSERT INTO oushu_table (name, description) VALUES
(&#039;Book1&#039;, &#039;This is a book about SQL.&#039;),
(&#039;Book2&#039;, &#039;Learn SQL the easy way.&#039;),
(&#039;Book3&#039;, &#039;Advanced SQL techniques.&#039;);
*/
-- 初始化计数器
total_count := 0;
matched_count := 0;
RAISE NOTICE &#039;Initialization: total_count = %, matched_count = %&#039;, total_count, matched_count;

-- 简单查询，计算总记录数
SELECT COUNT(*) INTO total_count FROM oushu_table;
RAISE NOTICE &#039;Total records in table: %&#039;, total_count;

-- 打开游标
OPEN cur;
RAISE NOTICE &#039;Cursor opened for search term: %&#039;, search_term;

-- 处理游标中的数据
LOOP
FETCH cur INTO rec;
EXIT WHEN NOT FOUND;
-- 复杂查询：检查记录是否匹配搜索词
IF rec.description LIKE &#039;%&#039; || search_term || &#039;%&#039; THEN
matched_count := matched_count + 1;
END IF;
END LOOP;

-- 关闭游标
CLOSE cur;
RAISE NOTICE &#039;Cursor closed&#039;;

-- 返回匹配的记录
RETURN QUERY SELECT * FROM oushu_table WHERE description LIKE &#039;%&#039; || search_term || &#039;%&#039;;
RAISE NOTICE &#039;Returning records that match search term: %&#039;, search_term;

END;
$$ LANGUAGE plpgsql;
