-- 创建表
CREATE TABLE IF NOT EXISTS my_table (
id SERIAL PRIMARY KEY,
name VARCHAR(100),
description TEXT
);

-- 向表中插入数据
INSERT INTO my_table (name, description) VALUES
(&#039;Book1&#039;, &#039;This is a book about SQL.&#039;),
(&#039;Book2&#039;, &#039;Learn SQL the easy way.&#039;),
(&#039;Book3&#039;, &#039;Advanced SQL techniques.&#039;);

-- 调用存储过程
SELECT * FROM example_procedure(&#039;SQL&#039;);
-- 获取输出参数的值
SELECT total_count, matched_count FROM example_procedure(&#039;SQL&#039;);
